  /* ── Blog: Stock Transfert Pro ── */
  "blog.stp.hero.title": "Stock Transfert Pro: the <span>Shopify</span> app for transfers between locations",
  "blog.stp.hero.text": "<strong>Shopify multi-location app</strong> available on the Shopify App Store since <time datetime=\"2026-06-03\">3 June 2026</time>. Transfer inventory between stores and warehouses, with smart drafts and point-of-sale receiving.",
  "blog.stp.hero.text2": "From <strong>$12/month</strong>, <strong>14-day</strong> free trial.",
  "blog.stp.hero.cta_app": "View the app on the Shopify App Store",
  "blog.stp.hero.cta_contact": "Talk about your Shopify project",

  "blog.stp.intro": "<strong>Stock Transfert Pro</strong> is a <strong>Shopify multi-location app</strong> to manage inventory transfers between stores, warehouses and points of sale.",
  "blog.stp.intro.updated": "Published <time datetime=\"2026-06-03\">3 June 2026</time>, updated <time datetime=\"2026-06-26\">26 June 2026</time>, <strong>Julien Brazzalotto</strong>, app developer.",
  "blog.stp.stats.title": "Key figures (2026)",
  "blog.stp.stats.list": "<li><strong>Starter</strong>: <strong>$12/month</strong>, up to <strong>2 locations</strong></li><li><strong>Pro</strong>: <strong>$57/month</strong>, <strong>unlimited</strong> locations</li><li><strong>Pro+</strong>: <strong>$116/month</strong>, multi-horizon forecasts and Slack alerts</li><li><strong>Free trial</strong>: <strong>14 days</strong> on all plans</li>",

  "blog.stp.s1.kicker": "Why this app",
  "blog.stp.s1.title": "Filling the gap left by Stocky",
  "blog.stp.s1.p1": "<strong>Stocky</strong>, Shopify's historic inventory app, was <strong>removed from the Shopify App Store on 2 February 2026</strong>, with full shutdown planned for <strong>31 August 2026</strong>. Many multi-location merchants were left without a simple tool to manage inter-store transfers.",
  "blog.stp.s1.p2": "<strong>Stock Transfert Pro</strong> addresses this specific need: a tool <strong>focused on transfers</strong> between Shopify locations, designed for teams that actually move stock between warehouse and stores, or between shops in the same network. Official App Store launch on <strong>3 June 2026</strong>.",

  "blog.stp.s2.kicker": "Workflow",
  "blog.stp.s2.title": "Manual transfers with a clear status cycle",
  "blog.stp.s2.p1": "Each transfer links two <strong>Shopify locations</strong> and follows a readable cycle: <strong>draft</strong> → <strong>sent</strong> → <strong>received</strong>, with cancellation possible.",
  "blog.stp.s2.p1b": "On send, stock is <strong>removed</strong> at source. On receive, it is <strong>added</strong> at destination via the Shopify Admin API. Levels stay aligned with the real state.",
  "blog.stp.s2.p2": "<strong>Partial receipts</strong> are handled natively: quantities sent vs quantities actually received, discrepancies, staff notes. Everything goes into a <strong>complete audit log</strong> to trace who did what and when.",

  "blog.stp.s3.title": "Smart drafts: less manual calculation",
  "blog.stp.s3.p1": "Beyond manual entry, the app offers two suggestion engines to prepare a transfer in a few clicks:",
  "blog.stp.s3.li1": "<strong>From sales</strong>: analyzes orders over a chosen period, groups by variant, compares to target store stock.",
  "blog.stp.s3.li1b": "The app then suggests a draft by selecting the best source, the one that actually has available stock.",
  "blog.stp.s3.li2": "<strong>From stock targets</strong> (Pro and Pro+ plans): you set targets per variant and location; the app calculates the shortfall and suggests a transfer to reach the target.",
  "blog.stp.s3.p2": "You stay in control: a generated draft remains a draft, editable and manually validated before sending.",

  "blog.stp.s4.title": "POS receiving, multilingual interface",
  "blog.stp.s4.p1": "A <strong>mobile-optimized view</strong> lets store staff validate incoming transfers directly from a phone or POS tablet, without going back to the office. The POS extension supports <strong>scanning</strong> and <strong>field validation</strong>.",
  "blog.stp.s4.p2": "The interface is translated into <strong>5 languages</strong> and automatically follows the Shopify admin language: <strong>French, English, Spanish, German, Italian</strong>.",

  "blog.stp.s5.kicker": "Beyond transfers",
  "blog.stp.s5.title": "Forecasts, alerts and AI (Pro and Pro+ plans)",
  "blog.stp.s5.p1": "The <strong>Pro</strong> plan adds <strong>30-day</strong> stock forecasting with a simple engine, a <strong>daily email alert summary</strong> and <strong>90-day sales history</strong>. Enough for most multi-location stores.",
  "blog.stp.s5.p2": "The <strong>Pro+</strong> plan goes further for mature merchants:",
  "blog.stp.s5.li1": "<strong>Multi-horizon</strong> forecast (14, 30 and 60 days), with breakdown <strong>by location</strong> (POS + warehouse).",
  "blog.stp.s5.li2": "<strong>EWMA + seasonality + multi-country events</strong> statistical engine.",
  "blog.stp.s5.li3": "Detailed <strong>revenue at risk</strong> indicator, trend and sparkline.",
  "blog.stp.s5.li4": "<strong>Email</strong> alerts (daily, weekly or immediate) and <strong>Slack</strong> alerts.",
  "blog.stp.s5.li5": "<strong>LLM AI BYOK</strong> (\"Bring Your Own Key\") option: connect your own OpenAI, Anthropic or Gemini key.",
  "blog.stp.s5.li5b": "The app generates contextual recommendations. The key is encrypted server-side. If AI is unavailable, the app falls back to deterministic calculations.",

  "blog.stp.s6.kicker": "Pricing",
  "blog.stp.s6.title": "Three plans, 14-day free trial",
  "blog.stp.s6.p": "All plans are billed in USD, monthly via Shopify Billing. <strong>14-day</strong> free trial on each plan.",
